import React, { useState } from 'react';
import { Link, Outlet, useNavigate } from 'react-router-dom';
import { useAuth } from '../../components/AuthContext';
import './AdminLayout.css';

const AdminLayout = () => {
    const [sidebarOpen, setSidebarOpen] = useState(true);
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/');
    };

    return (
        <div className="admin-layout">
            {/* Sidebar */}
            <div className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
                <div className="sidebar-header">
                    <h2>AutoVip Admin</h2>
                    <button onClick={() => setSidebarOpen(!sidebarOpen)} className="toggle-sidebar">
                        {sidebarOpen ? '◀' : '▶'}
                    </button>
                </div>
                
                <div className="admin-info">
                    <p>Xin chào,</p>
                    <strong>{user?.fullname}</strong>
                    <span className="admin-badge">Admin</span>
                </div>
                
                <nav className="sidebar-nav">
                    <Link to="/admin" className="nav-item">
                        📊 Dashboard
                    </Link>
                    <Link to="/admin/cars" className="nav-item">
                        🚗 Quản lý xe
                    </Link>
                    <Link to="/admin/users" className="nav-item">
                        👥 Quản lý người dùng
                    </Link>
                    <Link to="/admin/testdrives" className="nav-item">
                        📅 Lịch lái thử
                    </Link>
                    <Link to="/admin/reviews" className="nav-item">
                        ⭐ Đánh giá
                    </Link>
                    <Link to="/admin/contacts" className="nav-item">
                        📧 Liên hệ
                    </Link>
                    <Link to="/admin/news" className="nav-item">
                        📰 Tin tức
                    </Link>
                </nav>
                
                <div className="sidebar-footer">
                    <Link to="/" className="nav-item">
                        🏠 Về trang chủ
                    </Link>
                    <button onClick={handleLogout} className="logout-btn">
                        🚪 Đăng xuất
                    </button>
                </div>
            </div>
            
            {/* Main Content */}
            <div className={`main-content ${sidebarOpen ? '' : 'expanded'}`}>
                <Outlet />
            </div>
        </div>
    );
};

export default AdminLayout;
